/* Return the largest sum of any contiguous subarray in the vector x.
   Example: input: [-2, 1, -3, 4, -1, 2, 1, -5, 4] → output: 6
*/
int maximumSubarray(const std::vector<int>& x) {
    // If the input is empty, the maximum subarray is undefined for this problem.
    // Use the most negative int as the initial value.
    int max_so_far = std::numeric_limits<int>::lowest();
    int current_max = 0;

    // Single pass Kadane’s algorithm
    for (int value : x) {
        current_max = std::max(value, current_max + value);
        max_so_far  = std::max(max_so_far, current_max);
    }
    return max_so_far;
}
