inline int edgeCount(const std::vector<int>& A, std::size_t N)
{
    // Simple edge case handling
    if (N == 0) return 0;

    int total = 0;
    // Parallelize the double loop. Using reduction to avoid atomic overhead.
    #pragma omp parallel for collapse(2) reduction(+:total) schedule(static)
    for (std::size_t i = 0; i < N; ++i)
    {
        const std::size_t row_offset = i * N;
        for (std::size_t j = 0; j < N; ++j)
        {
            // Only IF there is an edge we increment
            total += (A[row_offset + j] != 0);
        }
    }
    return total;
}
