#include <omp.h>
#include <immintrin.h>   // for SIMD

// Element‑wise square using OpenMP + optional AVX2 on x86_64
void squareEach(std::vector<int> &x) {
    const size_t n = x.size();
    if (n == 0) return;

    // If the data is large enough, use SIMD on the bulk part
    const size_t simdStep = 8;          // 8 * 32‑bit = 256 bits (AVX2)
    const size_t simdHead = n / simdStep * simdStep;

    #pragma omp parallel
    {
        // SIMD chunk (shareable across threads using static schedule)
        #pragma omp for schedule(static)
        for (size_t i = 0; i < simdHead; i += simdStep) {
            __m256i vec = _mm256_loadu_si256(reinterpret_cast<const __m256i*>(&x[i]));
            vec = _mm256_mullo_epi32(vec, vec);
            _mm256_storeu_si256(reinterpret_cast<__m256i*>(&x[i]), vec);
        }

        // Remaining elements processed by each thread in a thread‑local loop
        #pragma omp for schedule(static)
        for (size_t i = simdHead; i < n; ++i) {
            const int v = x[i];
            x[i] = v * v;
        }
    }
}
