#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>

#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

// Optimised DFT
void dft(std::vector<double> const& x, std::vector<std::complex<double>> &output) {
    const std::size_t N = x.size();
    if (N == 0) {
        output.clear();
        return;
    }

    output.resize(N);
    const double two_pi = 2.0 * M_PI;

    // Pre‑compute the twiddle factor e^{-j*2π/N}
    const std::complex<double> w_step = std::polar(1.0, -two_pi / static_cast<double>(N));

    #pragma omp parallel for schedule(static)
    for (std::size_t k = 0; k < N; ++k) {
        std::complex<double> sum(0.0, 0.0);
        std::complex<double> w(1.0, 0.0);          // e^{-j*2π*k*0/N} == 1
        const std::complex<double> wp_k = std::pow(w_step, static_cast<double>(k));

        for (std::size_t n = 0; n < N; ++n) {
            sum += x[n] * w;
            w *= wp_k;                           // advance w by wp_k
        }
        output[k] = sum;
    }
}
