/* Count the number of pixels in image with each grayscale intensity.
   The vector `image` is a grayscale image with values 0-255.
   Store the results in `bins`.

   Example:
   input:  image=[2, 116, 201, 11, 92, 92, 201, 4, 2]
   output: [0, 0, 2, 0, 1, ...] */
inline void pixelCounts(std::vector<int> const& image,
                        std::array<std::size_t, 256>& bins)
{
    /* avoid race conditions by using a local copy per thread and
       merging them after the loop.  This eliminates expensive
       atomic operations. */
    const std::size_t nThreads = omp_get_max_threads();
    std::vector<std::array<std::size_t, 256>> local_bins(nThreads);

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        auto& local = local_bins[tid];
        // Zero-initialize local array
        std::fill(local.begin(), local.end(), 0);

        #pragma omp for schedule(static)
        for (std::size_t idx = 0; idx < image.size(); ++idx) {
            ++local[static_cast<std::uint8_t>(image[idx])];
        }
    }

    // Merge thread-local histograms into the final result
    for (const auto& local : local_bins) {
        for (std::size_t i = 0; i < 256; ++i) {
            bins[i] += local[i];
        }
    }
}
