#pragma once
#include <vector>
#include <algorithm>

// Compute the maximum node degree of an undirected graph given in
// a flattened row‑major adjacency matrix `A` of size N×N.
//
// The function is suitable for large dense matrices; it exploits
// loop‑unrolling, pointer arithmetic, and OpenMP parallelism
// to keep the CPU warm while preserving exact semantics.
//
// Note: The caller guarantees that all entries of `A` are
// either 0 or 1 (as the graph is un‑weighted and undirected).
//
// Author: C++ performance engineer
int maxDegree(std::vector<int> const &A, size_t N) {
    // Use a local variable for thread‑safe reduction
    int global_max = 0;

    // Parallelize outer loop over rows with OpenMP
    #pragma omp parallel for schedule(static) reduction(max:global_max)
    for (int i = 0; i < static_cast<int>(N); ++i) {
        // Process row `i`.  Use pointer arithmetic for speed.
        const int *row = &A[i * N];
        int sum = 0;

        // Unroll the inner loop to reduce branch overhead.
        int j = 0;
        int bound = static_cast<int>(N);
        int limit = bound & ~7; // floor to multiple of 8
        for (; j < limit; j += 8) {
            sum += row[j]   + row[j+1] + row[j+2] + row[j+3]
                + row[j+4] + row[j+5] + row[j+6] + row[j+7];
        }
        // Handle the remaining elements
        for (; j < bound; ++j) {
            sum += row[j];
        }

        // Keep track of the maximum degree seen so far
        if (sum > global_max) {
            global_max = sum;
        }
    }

    return global_max;
}
