/*
  Return the value of the smallest odd number in the vector `x`.
  If there is no odd number, return std::numeric_limits<int>::max().
  The implementation is fully parallelized using OpenMP.
*/
int smallestOdd(std::vector<int> const& x)
{
    // Fast exit for empty input
    if (x.empty())
        return std::numeric_limits<int>::max();

    const std::size_t n = x.size();

    // Compute the minimum odd number using a parallel reduction.
    // We perform the reduction manually to avoid any library
    // overhead and to keep the logic explicit.
    //
    // Each thread keeps a local minimum (initially INF).  
    // After the loop, a final reduction finds the global minimum.
    int global_min = std::numeric_limits<int>::max();

#pragma omp parallel
    {
        int local_min = std::numeric_limits<int>::max();
#pragma omp for schedule(static)
        for (std::size_t i = 0; i < n; ++i)
        {
            int v = x[i];
            // Only consider odd numbers
            if ((v & 1) == 1 && v < local_min)
                local_min = v;
        }
        // Atomic update of the global minimum
#pragma omp atomic update
        if (local_min < global_min)
            global_min = local_min;
    }

    return global_min;
}
