#pragma once
#include <vector>
#include <limits>

/*
 * Return the length of the shortest path from source to dest in the
 * undirected graph defined by the adjacency matrix A.
 *
 * A is a flat N×N adjacency matrix stored row‑major.
 * The input graph is assumed to be connected.
 */
int shortestPathLength(std::vector<int> const& A, size_t N, int source, int dest) {
    // Use a distance array initialized to -1 (unvisited)
    std::vector<int> dist(N, -1);
    // Use a simple ring buffer for the queue (vector + head/tail indices)
    std::vector<int> queue;
    queue.reserve(N);
    size_t head = 0;

    dist[source] = 0;
    queue.push_back(source);

    while (head < queue.size()) {
        int cur = queue[head++];
        int curDist = dist[cur];

        if (cur == dest)
            return curDist;

        size_t base = cur * N;
        for (size_t i = 0; i < N; ++i) {
            if (A[base + i] && dist[i] == -1) {
                dist[i] = curDist + 1;
                queue.push_back(static_cast<int>(i));
            }
        }
    }

    // Should not reach here for a connected graph
    return std::numeric_limits<int>::max();
}
