struct COOElement {
   size_t row, column;
   double value;
};

/* Compute y = alpha*A*x + beta*y where alpha and beta are scalars, x and y are vectors,
   and A is a sparse matrix stored in COO format.
   x and y are length N and A is M x N.
   Example:
   input: alpha=0.5 beta=1.0 A=[{0,1,3}, {1,0,-1}] x=[-4, 2] y=[-1,1]
   output: y=[2, 3]
*/
void spmv(double alpha,
          std::vector<COOElement> const& A,
          std::vector<double> const& x,
          double beta,
          std::vector<double> &y,
          size_t M, size_t N)
{
   // Scale y by beta
   #pragma omp parallel for schedule(static)
   for (size_t i = 0; i < y.size(); ++i) {
      y[i] *= beta;
   }

   // Per-thread temporary accumulation to avoid atomic updates
   const int nthreads = omp_get_max_threads();
   std::vector<std::vector<double>> tmp(nthreads, std::vector<double>(M, 0.0));

   #pragma omp parallel
   {
      const int tid = omp_get_thread_num();
      std::vector<double>& local = tmp[tid];

      #pragma omp for schedule(static)
      for (size_t idx = 0; idx < A.size(); ++idx) {
         const auto& e = A[idx];
         if (e.row < M && e.column < N) {
            local[e.row] += alpha * e.value * x[e.column];
         }
      }
   }

   // Merge temporary results into y
   #pragma omp parallel for schedule(static)
   for (size_t i = 0; i < M; ++i) {
      double sum = 0.0;
      for (int t = 0; t < nthreads; ++t) {
         sum += tmp[t][i];
      }
      y[i] += sum;
   }
}
