/// Counts how many strings in `s` start with each lower‑case letter.
/// The result is written to the 26‑entry array `bins` (0 ∵ ‘a’, …, 25 ∵ ‘z’).
///
/// The implementation is fully deterministic and produces exactly the same
/// final histogram as the sequential reference implementation.  It uses a
/// thread‑private local buffer per OpenMP thread to avoid contention, then
/// merges the partial counts at the end.  The code works for very large
/// vectors (`size_t` indices) and runs correctly on a GCC 11+ compiler with
/// `-fopenmp -O2` on a modern x86‑64 multi‑core system.
inline void firstLetterCounts(std::vector<std::string> const& s,
                              std::array<size_t, 26> &bins)
{
    // Reset output array (required by the harness).
    std::fill(bins.begin(), bins.end(), 0);

    // Work inside the parallel region to allow thread‑private arrays.
    #pragma omp parallel
    {
        // Each thread gets its own 26‑entry buffer to avoid atomic updates.
        std::array<size_t, 26> local = {0};

        // Parallel loop: each iteration is independent and safe to run
        // without synchronisation (since we use thread‑private local buffers).
        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < s.size(); ++i) {
            // In the original code the first byte of the string is always
            // a lower‑case ASCII character.  No bounds checking is needed.
            char c = s[i][0];
            // Compute the index ‘0’…‘25’.
            std::size_t idx = static_cast<unsigned char>(c) - 'a';
            // Guard against possible out‑of‑range values: this keeps the
            // behaviour identical to the reference (undefined behaviour
            // would also be UB, but we protect against accidental misuse).
            if (idx < 26) {
                ++local[idx];
            }
        }

        // Merge per‑thread histograms into the global result.
        #pragma omp critical
        {
            for (std::size_t k = 0; k < 26; ++k) {
                bins[k] += local[k];
            }
        }
    }
}
