#pragma once
#include <array>
#include <vector>
#include <cstddef>
#include <omp.h>

struct Point {
    double x, y;
};

/* Count cartesian points per quadrant.
   input: points vector
   output: bins[0] = Q1, bins[1] = Q2, bins[2] = Q3, bins[3] = Q4
*/
void countQuadrants(std::vector<Point> const& points, std::array<std::size_t, 4> &bins) {
    // clear output bins
    bins = {0, 0, 0, 0};

    // Number of threads, max 8 as per environment
    int const nthreads = 8;
    // per-thread accumulators
    std::vector<std::array<std::size_t, 4>> thread_bins(nthreads);
    for (auto &t : thread_bins) t = {0, 0, 0, 0};

#pragma omp parallel num_threads(nthreads)
    {
        int const tid = omp_get_thread_num();
        std::array<std::size_t, 4>& local = thread_bins[tid];

        // Distribute work among threads; static schedule gives each thread a contiguous chunk
#pragma omp for schedule(static)
        for (std::size_t i = 0; i < points.size(); ++i) {
            const Point &p = points[i];
            if (p.x >= 0.0) {
                if (p.y >= 0.0) {
                    ++local[0];          // Q1
                } else {
                    ++local[3];          // Q4
                }
            } else {
                if (p.y >= 0.0) {
                    ++local[1];          // Q2
                } else {
                    ++local[2];          // Q3
                }
            }
        }
    }

    // Reduce per-thread counts into global bins
