#include <algorithm>
#include <cstddef>

struct COOElement {
    std::size_t row, column;
    double value;
};

/* Compute Y = A * X where A and X are sparse matrices in COO format.
 * Y is returned as a dense MxN matrix in row-major order.
 * The algorithm hashes the X matrix by its row index to obtain O(1)
 * look‑ups during the multiplication, and parallelizes the outer loop
 * over the rows of A.  The exact semantics of the original routine are
 * preserved.
 */
static void spmm(std::vector<COOElement> const& A,
                 std::vector<COOElement> const& X,
                 std::vector<double>& Y,
                 std::size_t M, std::size_t K, std::size_t N)
{
    Y.assign(M * N, 0.0);

    /* Build a hash map from X.row → list of elements in that row */
    std::unordered_map<std::size_t, std::vector<COOElement>> rows_of_X;
    rows_of_X.reserve(K * 2);                     // reduce rehashes
    for (auto const& e : X) {
        rows_of_X[e.row].push_back(e);
    }

    /* Parallel over the non‑zero elements of A.
       Each thread produces updates only to its own row of Y,
       so no synchronization is required. */
#pragma omp parallel for schedule(dynamic)
    for (std::ptrdiff_t a_idx = 0; a_idx < static_cast<std::ptrdiff_t>(A.size()); ++a_idx) {
        auto const& a = A[a_idx];
        auto it = rows_of_X.find(a.column);
        if (it == rows_of_X.end()) continue;          // no matching x

        const std::vector<COOElement>& xVec = it->second;
        double aVal = a.value;
        std::size_t aRow = a.row;
        std::size_t rowOffset = aRow * N;

        for (auto const& x : xVec) {
            Y[rowOffset + x.column] += aVal * x.value;
        }
    }
}
