/* Return the distance between the closest two elements in the vector x.
   Example:
   input: [7, 3, 9, 12, 31, 1]
   output: 2
*/
double closestPair(std::vector<double> const& x) {
    const std::size_t n = x.size();
    if (n < 2) return 0.0;

    const double *const data = x.data();
    double best = std::numeric_limits<double>::infinity();

    /* Parallel double–nested loop.
       The outer loop is split across threads.  Within each
       iteration we scan the remaining points using a simple
       sequential inner loop and keep the best distance found
       by that thread.  The final result is obtained via a
       reduction on the local minima. */
#pragma omp parallel
    {
        double local_best = std::numeric_limits<double>::infinity();

#pragma omp for schedule(static)
        for (std::size_t i = 0; i < n - 1; ++i) {
            const double ai = data[i];
            for (std::size_t j = i + 1; j < n; ++j) {
                const double dist = std::abs(ai - data[j]);
                if (dist < local_best) {
                    local_best = dist;
                    if (local_best == 0.0) break; // cannot improve
                }
            }
        }

        /* Reduce local bests to the global best */
#pragma omp atomic min
        best = std::min(best, local_best);
    }

    return best;
}
