#pragma once
#include <vector>
#include <cstdint>
#include <numeric>
#include <omp.h>

/* Compute the prefix sum of the vector `x` into `output`.
   The function preserves the inclusive scan semantics:
   output[i] = x[0] + … + x[i]
   The implementation is thread‑parallel.
*/
inline void prefixSum(std::vector<int64_t> const& x,
                      std::vector<int64_t>      &output)
{
    size_t n = x.size();
    if (n == 0) return;

    // Ensure the output vector has the proper size.
    output.resize(n);

    // Determine the number of threads.
    int num_threads = omp_get_max_threads();

    // Work per thread.
    std::vector<size_t>  chunk_starts(num_threads);
    std::vector<size_t>  chunk_ends  (num_threads);
    std::vector<int64_t> thread_sums (num_threads, 0);

    // Partition the range into almost equal chunks.
    size_t chunk_size = (n + num_threads - 1) / num_threads;
    size_t start = 0;
    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        size_t local_start = tid * chunk_size;
        size_t local_end   = std::min(local_start + chunk_size, n);

        if (local_start >= n) {
            chunk_starts[tid] = chunk_ends[tid] = n;
        } else {
            chunk_starts[tid] = local_start;
            chunk_ends  [tid] = local_end;
            // Inclusive scan within the chunk.
            int64_t sum = 0;
            for (size_t i = local_start; i < local_end; ++i) {
                sum += x[i];
                output[i] = sum;
            }
            thread_sums[tid] = sum;
        }
    }

    // Prefix sum of thread_sums to get the offset for each chunk.
    std::vector<int64_t> offsets(num_threads);
    int64_t acc = 0;
    for (int i = 0; i < num_threads; ++i) {
        offsets[i] = acc;
        acc += thread_sums[i];
    }

    // Add the offset to each chunk (except the first).
    #pragma omp parallel for schedule(static)
    for (int tid = 0; tid < num_threads; ++tid) {
        size_t local_start = chunk_starts[tid];
        size_t local_end   = chunk_ends  [tid];
        int64_t offset = offsets[tid];
        if (offset == 0) continue;           // first chunk already correct
        for (size_t i = local_start; i < local_end; ++i) {
            output[i] += offset;
        }
    }
}
