    if (bins.size() != 10) {
        /* In case the caller passes a non‑10 element array, zero‑extend. */
        std::fill(bins.begin(), bins.end(), 0);
    } else {
        std::fill(bins.begin(), bins.end(), 0);
    }

    /* Determine the number of threads available to OpenMP. 2‑thread
       execution is generally enough on the target platform, but the
       parallelisation overhead is amortised over a large input. */
    const std::size_t n = x.size();
    if (n == 0) return;

    /* Allocate a small per‑thread temporary array for the reduction. */
    const int num_th = static_cast<int>(omp_get_max_threads());
    std::vector<std::array<std::size_t, 10>> local_bins(num_th);
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        auto& lb = local_bins[tid];
        // zero initialisation inside each thread
        std::fill(lb.begin(), lb.end(), 0);

        /* The loop is split into contiguous blocks to minimise false
           sharing.  `schedule(static, 1024)` gives a good trade‑off
           between load‑balance and cache traffic on modern CPUs. */
        #pragma omp for schedule(static, 1024)
        for (std::size_t i = 0; i < n; ++i) {
            /* X is in the range [0, 100] per the contract – 100 */
            /* would map to bin 10 which is out of range; we ignore it. */
            const std::size_t bin = static_cast<std::size_t>(x[i] / 10.0);
            if (bin < 10u) ++lb[bin];
        }
    }

    /* Combine the local bins into the output array. */
    for (int t = 0; t < num_th; ++t) {
        const auto& lb = local_bins[t];
        for (std::size_t b = 0; b < 10; ++b) bins[b] += lb[b];
    }
}
