#pragma once
#include <vector>
#include <cstddef>
#include <algorithm>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/*
 * Factorize the sparse matrix A into A = LU where
 * L is a lower triangular matrix and U is an upper triangular matrix.
 * A is given in COO format; L and U are returned in row‑major 1‑D arrays.
 *
 * Parameters
 *   A   : input COO matrix (size M)
 *   L   : output lower triangular matrix (size N*N), must be pre‑allocated
 *   U   : output upper triangular matrix (size N*N), must be pre‑allocated
 *   N   : dimension of the square matrix
 *
 * The function preserves the exact numerical behaviour of the reference
 * implementation but is written to run efficiently on a modern x86‑64
 * machine with 8 hardware threads and GCC 11+ with OpenMP support.
 */
inline void luFactorize(const std::vector<COOElement>& A,
                        std::vector<double>& L,
                        std::vector<double>& U,
                        size_t N)
{
    // Flattened dense representation of A to allow O(1) access.
    std::vector<double> fullA(N * N, 0.0);
    for (const auto& e : A)
        fullA[e.row * N + e.column] = e.value;

    // Zero initialise output matrices
    std::fill(L.begin(), L.end(), 0.0);
    std::fill(U.begin(), U.end(), 0.0);

    // LU factorisation: row‑wise (destination dependence is only on already
    // processed rows; hence we can parallelise the outer loop).
    #pragma omp parallel for schedule(static)
    for (ptrdiff_t i = 0; i < static_cast<ptrdiff_t>(N); ++i) {
        const ptrdiff_t iN = i * static_cast<ptrdiff_t>(N);

        // Precise aliases for speed
        double* const Lrow = &L[iN];
        double* const Urow = &U[iN];
        const double* const Ai = &fullA[iN];

        // Compute row i of U and L
        for (size_t j = 0; j < N; ++j) {
            if (j >= i) {
                double sij = Ai[j];
                for (size_t k = 0; k < i; ++k) {
                    sij -= Lrow[k] * U[k * N + j];
                }
                Urow[j] = sij;
            }
            if (i > j) {
                double sij = Ai[j];
                for (size_t k = 0; k < j; ++k) {
                    sij -= Lrow[k] * U[k * N + j];
                }
                // U[j*N + j] is already computed by the j‑th outer loop
                sij /= U[j * N + j];
                Lrow[j] = sij;
            }
        }
        // Diagonal of L is unity
        Lrow[i] = 1.0;
    }
}
