/*
 * Compute one iteration of a 3‑point 1‑D Jacobi stencil on `input`.
 * Exact behaviour: out[i] = (in[i-1] + in[i] + in[i+1]) / 3,
 * with the convention that out[0] uses 0 in place of in[-1] and
 * out[last] uses 0 in place of in[last+1].
 *
 * Parallelised with OpenMP and vectorised by the compiler.
 * No change to the public API.
 */
inline void jacobi1D(std::vector<double> const& input,
                     std::vector<double>&   output)
{
    const std::size_t N = input.size();

    /* Treat the first and last elements separately to avoid branch penalties. */
    if (N == 0)          // nothing to do
        return;

    /* First element (boundary with zero left). */
    output[0] = (input[0] + (N > 1 ? input[1] : 0.0)) / 3.0;

    /* Last element (boundary with zero right). */
    if (N > 1)
        output[N-1] = (input[N-2] + input[N-1]) / 3.0;

    /* Inner elements: parallel loop, static schedule for cache locality. */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 1; i+1 < N; ++i) {
        // compiler will auto‑vectorise this simple sum
        output[i] = (input[i-1] + input[i] + input[i+1]) / 3.0;
    }
}
