#pragma once
#include <vector>
#include <algorithm>

// Union‑Find (Disjoint Set Union) data structure
class DSU {
public:
    DSU(size_t n) : parent(n), rank(n, 0), sz(n, 1) {
        for (size_t i = 0; i < n; ++i) parent[i] = i;
    }

    size_t find(size_t x) {
        size_t p = parent[x];
        while (p != parent[p]) {
            parent[p] = parent[parent[p]];
            p = parent[p];
        }
        parent[x] = p;
        return p;
    }

    void unite(size_t a, size_t b) {
        size_t ra = find(a);
        size_t rb = find(b);
        if (ra == rb) return;
        if (rank[ra] < rank[rb]) {
            parent[ra] = rb;
            sz[rb] += sz[ra];
        } else if (rank[ra] > rank[rb]) {
            parent[rb] = ra;
            sz[ra] += sz[rb];
        } else {
            parent[rb] = ra;
            sz[ra] += sz[rb];
            ++rank[ra];
        }
    }

    int componentSize(size_t x) {
        return sz[find(x)];
    }

private:
    std::vector<size_t> parent;
    std::vector<int>    rank;
    std::vector<int>    sz;
};

/* Return the number of vertices in the largest component of the graph defined by the adjacency matrix A.
   A is an NxN adjacency matrix stored in row‑major. */
int largestComponent(std::vector<int> const& A, size_t N) {
    DSU dsu(N);
    // Only need to examine the upper triangle (or lower) to avoid duplicate edges
    for (size_t i = 0; i < N; ++i) {
        size_t base = i * N;
        for (size_t j = i + 1; j < N; ++j) {
            if (A[base + j] == 1) dsu.unite(i, j);
        }
    }

    // Find the maximum component size
    int maxSize = 0;
    // We can reuse dsu.sz but it only contains sizes for roots.
    for (size_t i = 0; i < N; ++i) {
        if (dsu.find(i) == i) {          // i is a root
            maxSize = std::max(maxSize, dsu.componentSize(i));
        }
    }
    return maxSize;
}
