/* Set each cell's value to 1 if it has exactly one neighboring cell that is 1, otherwise set it to 0.
   The grid is stored row‑major in a single dimension vector. */
void cellsXOR(std::vector<int> const& input, std::vector<int> &output, size_t N)
{
    const int*   in  = input.data();
    int*         out = output.data();
    const size_t stride = N;                         // row stride

    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const size_t idx = i * stride;
        const int* rowUp   = (i > 0)     ? in + (i - 1) * stride : nullptr;
        const int* rowDown = (i + 1 < N) ? in + (i + 1) * stride : nullptr;
        int* outRow = out + idx;

        for (size_t j = 0; j < N; ++j) {
            int cnt = 0;
            if (rowUp   && rowUp[j]   == 1) ++cnt;   // up
            if (rowDown && rowDown[j] == 1) ++cnt;   // down

            // left
            if (j > 0 && in[idx + j - 1] == 1) ++cnt;
            // right
            if (j + 1 < N && in[idx + j + 1] == 1) ++cnt;

            outRow[j] = (cnt == 1) ? 1 : 0;
        }
    }
}
