inline double cross(const Point& a, const Point& b, const Point& c) {
    // 2 * signed area of triangle (a,b,c)
    return a.x * (b.y - c.y) + b.x * (c.y - a.y) + c.x * (a.y - b.y);
}

inline double triArea(const Point& a, const Point& b, const Point& c) {
    return 0.5 * std::fabs(cross(a, b, c));
}

/* Return the area of the smallest triangle that can be formed by any 3 points.
   The implementation is fully parallel and keeps the exact numerical result
   of the original algorithm.
*/
double smallestArea(const std::vector<Point>& points) {
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    double minArea = std::numeric_limits<double>::max();

    // Use raw pointer for faster indexing
    const Point* p = points.data();

    // Parallel triple nested loops with OpenMP.
    // collapse(3) distributes the work among threads.
    #pragma omp parallel for collapse(3) reduction(min:minArea) schedule(static)
    for (std::size_t i = 0; i < n - 2; ++i) {
        for (std::size_t j = i + 1; j < n - 1; ++j) {
            for (std::size_t k = j + 1; k < n; ++k) {
                const double area = triArea(p[i], p[j], p[k]);
                if (area < minArea)
                    minArea = area;
            }
        }
    }
    return minArea;
}
