#pragma once
#include <vector>
#include <algorithm>
#include <cmath>
#include <cstddef>
#include <omp.h>

struct COOElement {
   std::size_t row, column;
   double value;
};

/*
 * Solve the sparse linear system Ax=b for x.
 * A: COO format, b: RHS, x: solution (output), N: size.
 *
 * This implementation builds a dense matrix once (O(N²) memory),
 * then performs Gaussian elimination with partial pivoting.
 * Parallelization is done on the outermost loops that are
 * independent; the same algorithmic behaviour as the reference
 * implementation is preserved.
 */
static inline void solveLinearSystem(std::vector<COOElement> const& A,
                                     std::vector<double> const& b,
                                     std::vector<double> &x,
                                     std::size_t N)
{
   /* Allocate dense matrix in row-major order.
    * std::vector<double> is used for zero‑initialisation.
    */
   std::vector<double> mat(N * N, 0.0);
   std::vector<double> rhs = b;           // copy of b (local workspace)

   /* Fill the dense matrix from COO data */
   for (const auto &e : A)
      mat[e.row * N + e.column] = e.value;

   /* Gaussian elimination with partial pivoting */
   for (std::size_t i = 0; i < N; ++i)
   {
      /* ---- Pivot search ---- */
      std::size_t maxRow = i;
      double   maxVal = std::abs(mat[i * N + i]);

      #pragma omp parallel for reduction(max:maxVal,start(maxVal))
      for (std::size_t k = i + 1; k < N; ++k)
      {
         double val = std::abs(mat[k * N + i]);
         if (val > maxVal)
         {
            maxVal = val;
            #pragma omp atomic capture
            maxRow = static_cast<std::size_t>(k);
         }
      }

      /* ---- Swap rows i and maxRow (including RHS) ---- */
      if (maxRow != i)
      {
         for (std::size_t j = i; j < N; ++j)
            std::swap(mat[i * N + j], mat[maxRow * N + j]);

         std::swap(rhs[i], rhs[maxRow]);
      }

      /* ---- Make entries below pivot zero ---- */
      const double pivot = mat[i * N + i];
      #pragma omp parallel for
      for (std::size_t k = i + 1; k < N; ++k)
      {
         double factor = -mat[k * N + i] / pivot;
         for (std::size_t j = i; j < N; ++j)
         {
            if (i == j)
               mat[k * N + j] = 0.0;
            else
               mat[k * N + j] += factor * mat[i * N + j];
         }
         rhs[k] += factor * rhs[i];
      }
   }

   /* ---- Back substitution ---- */
   x.resize(N);
   for (int i = static_cast<int>(N) - 1; i >= 0; --i)
   {
      double sum = rhs[i];
      #pragma omp parallel for reduction(-:sum)
      for (int j = i + 1; j < static_cast<int>(N); ++j)
         sum -= mat[i * N + j] * x[j];

      x[i] = sum / mat[i * N + i];
   }
}
