    // lower hull
    for (std::size_t i = 0; i < n; ++i) {
        while (k >= 2 && cross(hullVec[k - 2], hullVec[k - 1], pts[i]) <= 0.0) --k;
        hullVec[k++] = pts[i];
    }

    // upper hull
    std::size_t t = k + 1;
    for (std::size_t i = n; i-- > 1; ) {          // i from n-1 to 1
        while (k >= t && cross(hullVec[k - 2], hullVec[k - 1], pts[i - 1]) <= 0.0) --k;
        hullVec[k++] = pts[i - 1];
    }

    hullVec.resize(k - 1);
    hull.swap(hullVec);
}
