/* Optimal LU factorization: A = L * U
   The matrix A is overwritten in place.
   The algorithm remains exactly the same as the reference implementation. */
inline void luFactorize(std::vector<double> &A, std::size_t N) {
    const std::size_t N2 = N * N;                    // avoid recompute
    const std::size_t stride = N;                    // row stride

    for (std::size_t k = 0; k < N; ++k) {
        const double pivot = A[k * stride + k];      // A[k][k]
        // Parallelise the elimination of rows below the pivot
#pragma omp parallel for schedule(static) if (N-k-1 > 0)
        for (std::size_t i = k + 1; i < N; ++i) {
            double *row_i = &A[i * stride];
            double factor = row_i[k] / pivot;         // L[i][k]
            row_i[k] = factor;                        // store L below diagonal

            double *row_k = &A[k * stride];
            // Update the remaining entries of the row:  A[i][j] -= factor * A[k][j]
            for (std::size_t j = k + 1; j < N; ++j) {
                row_i[j] -= factor * row_k[j];
            }
        }
    }
}
