/* Optimised radix‑2 FFT.
   Maintains the original behaviour: in‑place transformation of the input
   vector (copied from 'x'), a bit‑reversal permutation and a final
   split into real/imaginary components stored in 'r' and 'i'.
 */
inline void fft(std::vector<std::complex<double>> const& x,
                std::vector<double> &r, std::vector<double> &i)
{
    const size_t N = x.size();
    std::vector<std::complex<double>> a(x);          // work buffer
    std::vector<std::complex<double>> tmp(N);
    const size_t logN = static_cast<size_t>(std::log2(N));

    /* Pre‑compute twiddle factors for each stage */
    std::vector<std::vector<std::complex<double>>> twiddles(logN);
    for (size_t s = 0; s < logN; ++s) {
        size_t m = 1ULL << (s + 1);          // size of butterfly block
        size_t half = m >> 1;
        twiddles[s].resize(half);
        double angle = -M_PI / half;
        for (size_t k = 0; k < half; ++k)
            twiddles[s][k] = std::complex<double>(std::cos(k * angle),
                                                 std::sin(k * angle));
    }

    /* Cooley‑Tukey radix‑2 decimation‑in‑time */
    for (size_t s = 0; s < logN; ++s) {
        size_t m = 1ULL << (s + 1);
        size_t half = m >> 1;
        #pragma omp parallel for schedule(static)
        for (size_t j = 0; j < N; j += m) {
            for (size_t k = 0; k < half; ++k) {
                std::complex<double> t = twiddles[s][k] * a[j + k + half];
                tmp[j + k]       = a[j + k] + t;
                tmp[j + k + half] = a[j + k] - t;
            }
        }
        a.swap(tmp);
    }

    /* Bit‑reversal permutation */
    for (size_t i = 0; i < N; ++i) {
        size_t j = i;
        j = ((j & 0xaaaaaaaa) >> 1) | ((j & 0x55555555) << 1);
        j = ((j & 0xcccccccc) >> 2) | ((j & 0x33333333) << 2);
        j = ((j & 0xf0f0f0f0) >> 4) | ((j & 0x0f0f0f0f) << 4);
        j = ((j & 0xff00ff00) >> 8) | ((j & 0x00ff00ff) << 8);
        j = ((j >> 16) | (j << 16)) >> (32 - logN);
        if (j > i)
            std::iter_swap(a.begin() + i, a.begin() + j);
    }

    /* Split into real and imaginary parts */
    r.resize(N);
    i.resize(N);
    for (size_t k = 0; k < N; ++k) {
        r[k] = a[k].real();
        i[k] = a[k].imag();
    }
}
