struct Point {
    double x, y;
};

// Fast inline distance – no pow, only one sqrt per segment
inline double dist(const Point& a, const Point& b) {
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return std::sqrt(dx*dx + dy*dy);
}

// Cross product for orientation tests
inline double cross(const Point& o, const Point& a, const Point& b) {
    return (a.x - o.x)*(b.y - o.y) - (a.y - o.y)*(b.x - o.x);
}

/* Return the perimeter of the smallest convex polygon that contains all the points */
double convexHullPerimeter(std::vector<Point> const& points) {
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    // Make a copy and sort it (lexicographic order)
    std::vector<Point> pts = points;
    std::sort(pts.begin(), pts.end(), [](const Point& a, const Point& b){
        return (a.x < b.x) || (a.x == b.x && a.y < b.y);
    });

    // Build hull in a single vector
    std::vector<Point> hull;
    hull.reserve(2*n);

    // Lower hull
    for (const auto& p : pts) {
        while (hull.size() >= 2 &&
               cross(hull[hull.size()-2], hull.back(), p) <= 0.0) {
            hull.pop_back();
        }
        hull.push_back(p);
    }
    // Upper hull
    for (std::size_t i = n-1; i > 0; --i) {          // skip the last point again
        const Point& p = pts[i-1];
        while (hull.size() >= n+1 &&
               cross(hull[hull.size()-2], hull.back(), p) <= 0.0) {
            hull.pop_back();
        }
        hull.push_back(p);
    }
    // Last point is same as first, remove it
    hull.pop_back();

    // Compute perimeter (with OpenMP parallel reduction)
    double perim = 0.0;
    #pragma omp parallel for reduction(+:perim)
    for (std::size_t i = 0; i < hull.size(); ++i) {
        perim += dist(hull[i], hull[(i+1)%hull.size()]);
    }
    return perim;
}
