struct Element {
    std::size_t index;
    double value;
};

/*
 * Compute z = alpha*x + y where x and y are sparse vectors.
 * Both x and y are sorted by `index` and use the same zero‑indexed dense `z`.
 *
 * The implementation splits the work into two independent passes:
 *   1. Each entry of `x` is added to a temporary array `tmpX`.
 *   2. Each entry of `y` is added to a temporary array `tmpY`.
 * Both passes are parallelized with OpenMP.  The final dense result
 * is produced by a single linear combination of the two temporaries.
 *
 * This expression guarantees that each write to the same index from
 * `x` and `y` occurs in separate array updates, eliminating the need
 * for atomic operations or a critical section while still preserving
 * the exact numeric result of the sequential algorithm.
 */
void sparseAxpy(double alpha,
                const std::vector<Element>& x,
                const std::vector<Element>& y,
                std::vector<double>& z)
{
    // Ensure output vector is large enough.
    const std::size_t n = z.size();

    // Temporary storage for contributions from x and y.
    std::vector<double> tmpX(n, 0.0);
    std::vector<double> tmpY(n, 0.0);

    // Parallel accumulation from `x`.
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < x.size(); ++i) {
        const std::size_t idx = x[i].index;
        if (idx < n) {
            tmpX[idx] += alpha * x[i].value;
        }
    }

    // Parallel accumulation from `y`.
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < y.size(); ++i) {
        const std::size_t idx = y[i].index;
        if (idx < n) {
            tmpY[idx] += y[i].value;
        }
    }

    // Combine the two partial results into `z` in a single pass.
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        z[i] = tmpX[i] + tmpY[i];
    }
}
