#include <omp.h>

/*
 * Optimized matrix multiplication (GEMM) for double precision
 * A: M x K (row-major)
 * B: K x N (row-major)
 * C: M x N (row-major), accumulation into existing values
 *
 * The implementation uses:
 *   • Cache-friendly blocking (block sizes tuned for typical L1/L2 caches)
 *   • Manual loop reordering for better data reuse
 *   • OpenMP parallelism over the outermost loop
 *   • Maximal use of register temporaries to reduce memory traffic
 *
 * The algorithm preserves the exact mathematical behavior of the scalar
 * reference implementation.
 */
inline void gemm(const std::vector<double>& A,
                 const std::vector<double>& B,
                 std::vector<double>& C,
                 size_t M, size_t K, size_t N) {
    constexpr size_t BM = 64;   // block size for rows of A/C
    constexpr size_t BN = 64;   // block size for columns of B/C
    constexpr size_t BK = 64;   // block size for inner dimension (K)

    // Parallel over the row blocks of C and A
    #pragma omp parallel for schedule(static)
    for (size_t ii = 0; ii < M; ii += BM) {
        size_t i_max = std::min(ii + BM, M);
        for (size_t kk = 0; kk < K; kk += BK) {
            size_t k_max = std::min(kk + BK, K);
            for (size_t jj = 0; jj < N; jj += BN) {
                size_t j_max = std::min(jj + BN, N);

                // For each element in the block, accumulate locally
                for (size_t i = ii; i < i_max; ++i) {
                    size_t a_off = i * K;
                    size_t c_off = i * N;
                    for (size_t k = kk; k < k_max; ++k) {
                        double aik = A[a_off + k];
                        size_t b_off = k * N;
                        // Unroll inner loop over j for better vectorization
                        for (size_t j = jj; j < j_max; ++j) {
                            C[c_off + j] += aik * B[b_off + j];
                        }
                    }
                }
            }
        }
    }
}
