void solveLinearSystem(std::vector<double> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       size_t N)
{
    // Work on copies of A and b to avoid modifying the inputs
    std::vector<double> a = A;
    std::vector<double> bb = b;

    double* const a_ptr = a.data();
    double* const bb_ptr = bb.data();
    double* const x_ptr = x.data();

    // Gaussian elimination (upper‑triangular form)
    for (size_t i = 0; i < N - 1; ++i) {
        double diag = a_ptr[i * N + i];
        if (diag == 0.0) return;          // singular matrix – abort as original

        const double inv_diag = 1.0 / diag;

        // Parallelise the rows below the pivot
#pragma omp parallel for schedule(static)
        for (ptrdiff_t j = static_cast<ptrdiff_t>(i) + 1; j < static_cast<ptrdiff_t>(N); ++j) {
            double factor = a_ptr[j * N + i] * inv_diag;

            // Eliminate the pivot column and update the remainder of the row
            // Unrolled for a small constant factor
            for (size_t k = i; k < N; ++k) {
                a_ptr[j * N + k] -= factor * a_ptr[i * N + k];
            }
            bb_ptr[j] -= factor * bb_ptr[i];
        }
    }

    // Back‑substitution
    for (ptrdiff_t i = static_cast<ptrdiff_t>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        for (size_t j = static_cast<size_t>(i) + 1; j < N; ++j) {
            sum += a_ptr[i * N + j] * x_ptr[j];
        }
        x_ptr[i] = (bb_ptr[i] - sum) / a_ptr[i * N + i];
    }
}
