size_t findClosestToPi(std::vector<double> const& x) {
    const size_t n = x.size();
    if (n == 0) return 0;               // defensive, though not expected with the original interface

    double global_min = std::abs(x[0] - M_PI);
    size_t global_idx = 0;

    // Parallel reduction with a custom combiner
    #pragma omp parallel
    {
        double local_min = global_min;
        size_t local_idx = global_idx;

        #pragma omp for nowait
        for (size_t i = 0; i < n; ++i) {
            double d = std::abs(x[i] - M_PI);
            if (d < local_min) {
                local_min = d;
                local_idx = i;
            }
        }

        // Reduction step
        #pragma omp critical
        {
            if (local_min < global_min) {
                global_min = local_min;
                global_idx = local_idx;
            }
        }
    }

    return global_idx;
