bool xorContains(std::vector<int> const& x, std::vector<int> const& y, int val) {
    bool foundX = false;
    for (const int* p = x.data(), *end = p + x.size(); p != end; ++p) {
        if (*p == val) {
            foundX = true;
            // No need to search further in x
            break;
        }
    }

    bool foundY = false;
    for (const int* p = y.data(), *end = p + y.size(); p != end; ++p) {
        if (*p == val) {
            foundY = true;
            // No need to search further in y
            break;
        }
    }

    return foundX ^ foundY;
}
