            if (frac < 0.25)      ++local[0];
            else if (frac < 0.5)  ++local[1];
            else if (frac < 0.75) ++local[2];
            else                  ++local[3];
        }

        // combine thread‑local counts into the shared result
        #pragma omp critical
        {
            for (size_t k = 0; k < 4; ++k)
                bins[k] += local[k];
        }
    }
