    // for equal values as the reference algorithm.
    std::stable_sort(vals.begin(), vals.end(),
                     [](const auto& a, const auto& b) { return a.first < b.first; });

    // Scatter the ranks back into the output vector.  The loop is trivial
    // and can safely be parallelised with OpenMP.
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        ranks_[vals[i].second] = i;
    }
