/* Edge detection kernel */
constexpr int edgeKernel[9] = {
    -1, -1, -1,
    -1,  8, -1,
    -1, -1, -1
};

/* -----------------------------------------------------------------------
   Convolve a square grayscale image with the 3×3 edge‑kernel.
   The input image is stored row‑major in imageIn, the output in imageOut.
   Image dimensions are N×N.  Pixels outside the image are treated as zero.
   The result of each convolution is clamped to [0,255].
   ----------------------------------------------------------------------- */
inline void convolveKernel(std::vector<int> const& imageIn,
                           std::vector<int> &imageOut,
                           std::size_t N)
{
    const int  *in  = imageIn.data();
    int        *out = imageOut.data();

    /* Parallelise over rows.  Each thread processes a contiguous chunk of
       rows, avoiding false sharing on the output array. */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        const std::size_t row_off = i * N;
        for (std::size_t j = 0; j < N; ++j) {
            /* manual expansion of the 3×3 kernel to avoid bounds checks
               inside the innermost loops.  The four corner cases are
               handled explicitly; the central four pixels are handled
               with a small helper lambda. */
            int sum = 0;

            /* Row i-1 */
            if (i > 0) {
                std::size_t r = row_off - N;          // index of row i-1
                sum += edgeKernel[0] * (j > 0     ? in[r + j - 1] : 0);   // k=-1,l=-1
                sum += edgeKernel[1] *  in[r + j    ];                  // k=-1,l=0
                sum += edgeKernel[2] * (j + 1 < N ? in[r + j + 1] : 0);   // k=-1,l=1
            }

            /* Row i (center) */
            if (j > 0)   sum += edgeKernel[3] * in[row_off + j - 1];  // k=0,l=-1
            sum += edgeKernel[4] * in[row_off + j];                   // k=0,l=0
            if (j + 1 < N) sum += edgeKernel[5] * in[row_off + j + 1]; // k=0,l=1

            /* Row i+1 */
            if (i + 1 < N) {
                std::size_t r = row_off + N;          // index of row i+1
                sum += edgeKernel[6] * (j > 0     ? in[r + j - 1] : 0);   // k=1,l=-1
                sum += edgeKernel[7] *  in[r + j    ];                  // k=1,l=0
                sum += edgeKernel[8] * (j + 1 < N ? in[r + j + 1] : 0);   // k=1,l=1
            }

            /* Clip to [0,255] */
            out[row_off + j] = static_cast<int>(std::clamp(sum, 0, 255));
        }
    }
}
