#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Simulate one generation of Game of Life on `input`. Store the results in `output`.
   A cell is 1 if it is alive and 0 if it is dead.
   Rules:
     * Live cell with < 2 neighbors -> dead
     * Live cell with 2 or 3 neighbors -> live
     * Live cell with > 3 neighbors -> dead
     * Dead cell with exactly 3 neighbors -> live
   `input` and `output` are NxN grids stored in row-major order.
*/
inline void gameOfLife(std::vector<int> const& input,
                       std::vector<int>&       output,
                       std::size_t             N) noexcept
{
    // Fast access to underlying data
    const int* restrict in  = input.data();
    int*       restrict out = output.data();

    // Parallel loop over all cells. The collapse(2) yields a single
    // contiguous work‑sharing across both dimensions, minimising thread
    // overhead. GCC + OpenMP 4.5 yields efficient schedule.
    #pragma omp parallel for collapse(2) schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t base = i * N;
        for (std::size_t j = 0; j < N; ++j) {
            std::size_t idx = base + j;
            int sum = 0;

            // Neighbor indices – the bounds are checked just once.
            if (i > 0)         sum += in[idx - N];         // up
            if (i + 1 < N)     sum += in[idx + N];         // down
            if (j > 0)         sum += in[idx - 1];         // left
            if (j + 1 < N)     sum += in[idx + 1];         // right
            if (i > 0 && j > 0)            sum += in[idx - N - 1]; // up-left
            if (i > 0 && j + 1 < N)        sum += in[idx - N + 1]; // up-right
            if (i + 1 < N && j > 0)        sum += in[idx + N - 1]; // down-left
            if (i + 1 < N && j + 1 < N)    sum += in[idx + N + 1]; // down-right

            // Apply the rules.
            int cur = in[idx];
            if (cur == 1) {            // alive
                out[idx] = (sum == 2 || sum == 3) ? 1 : 0;
            } else {                   // dead
                out[idx] = (sum == 3) ? 1 : 0;
            }
        }
    }
}
