#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstdint>

#if !defined(M_PI)
#  define M_PI 3.14159265358979323846
#endif

static inline std::size_t log2_uint(unsigned int n)
{
    // n is power of two
    return static_cast<std::size_t>(std::log2(static_cast<double>(n)));
}

//--- Bit reversal table generation ------------------------------------
static std::vector<std::uint32_t> make_bitrev_table(std::size_t n)
{
    std::size_t logn = log2_uint(static_cast<unsigned int>(n));
    std::vector<std::uint32_t> rev(n);
    for (std::size_t i = 0; i < n; ++i)
    {
        std::uint32_t x = static_cast<std::uint32_t>(i);
        x = ((x & 0xaaaaaaaau) >> 1) | ((x & 0x55555555u) << 1);
        x = ((x & 0xccccccccu) >> 2) | ((x & 0x33333333u) << 2);
        x = ((x & 0xf0f0f0f0u) >> 4) | ((x & 0x0f0f0f0fu) << 4);
        x = ((x & 0xff00ff00u) >> 8) | ((x & 0x00ff00ffu) << 8);
        rev[i] = (x >> (32 - logn));
    }
    return rev;
}

//--- Pre‑computed twiddle factors --------------------------------------
static std::vector<std::vector<std::complex<double>>> make_twiddle_table(std::size_t n)
{
    std::size_t stages = log2_uint(static_cast<unsigned int>(n));
    std::vector<std::vector<std::complex<double>>> T(stages);
    for (std::size_t s = 0; s < stages; ++s)
    {
        std::size_t step = 1ULL << s;
        T[s].resize(step);
        double angle = -M_PI / static_cast<double>(n >> s);
        std::complex<double> w = std::polar(1.0, angle); // exp(i*angle)
        std::complex<double> v = 1.0;
        for (std::size_t k = 0; k < step; ++k)
        {
            T[s][k] = v;
            v *= w;
        }
    }
    return T;
}

//--- Fast FFT ---------------------------------------------------------
void fft(std::vector<std::complex<double>> const& x,
         std::vector<std::complex<double>> &output)
{
    std::size_t N = x.size();
    if (N == 0) { output.clear(); return; }
    output = x;                          // copy to output

    static std::vector<std::uint32_t> bitrev_cache;
    static std::vector<std::vector<std::complex<double>>> twiddle_cache;
    static std::size_t cache_n = 0;

    // Recreate tables if size changed
    if (cache_n != N)
    {
        cache_n = N;
        bitrev_cache = make_bitrev_table(N);
        twiddle_cache = make_twiddle_table(N);
    }

    // Bit‑reversal permutation
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
    {
        std::size_t j = bitrev_cache[i];
        if (j > i)
            std::swap(output[i], output[j]);
    }

    // Iterative radix‑2 Cooley–Tukey
    for (std::size_t s = 0; s < log2_uint(static_cast<unsigned int>(N)); ++s)
    {
        std::size_t step = 1ULL << s;
        std::size_t span = step << 1;
        const std::vector<std::complex<double>>& W = twiddle_cache[s];

        // Parallel over sub‑blocks
        #pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < N; k += span)
        {
            for (std::size_t j = 0; j < step; ++j)
            {
                std::size_t idx1 = k + j;
                std::size_t idx2 = idx1 + step;
                std::complex<double> a = output[idx1];
                std::complex<double> b = output[idx2] * W[j];
                output[idx1] = a + b;
                output[idx2] = a - b;
            }
        }
    }
}
