#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>
#include <immintrin.h>

/* Optimized 5‑point Jacobi stencil.
   The code keeps the identical functional behavior as the reference
   implementation while adding SIMD vectorisation, cache‑blocking,
   and OpenMP parallelisation.  No changes to the public API are made. */
inline void jacobi2D(std::vector<double> const& input,
                     std::vector<double> &output,
                     size_t N)
{
    const size_t block = 64;                    // size of a cache block (adjustable)
    constexpr double inv5 = 1.0 / 5.0;

    // Parallelise over the outer loop; each thread works on a contiguous
    // chunk of rows so that the inner loop can use SIMD without any
    // cross‑thread interference.
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        const size_t top    = (i > 0)     ? (i - 1) * N : SIZE_MAX; // sentinel for missing neighbour
        const size_t bottom = (i + 1 < N) ? (i + 1) * N : SIZE_MAX;
        const size_t cur    = i * N;

        /* SIMD processing of the interior columns.
           Process four columns at a time with AVX2 (256‑bit). */
        size_t j = 0;
        for (; j + 3 < N; j += 4)
        {
            __m256d v_cur  = _mm256_loadu_pd(&input[cur + j]);

            /* Load neighbours: need to guard against boundary */
            __m256d v_up   = (top == SIZE_MAX) ?
                               _mm256_setzero_pd() :
                               _mm256_loadu_pd(&input[top + j]);

            __m256d v_down = (bottom == SIZE_MAX) ?
                               _mm256_setzero_pd() :
                               _mm256_loadu_pd(&input[bottom + j]);

            /* Left neighbour */
            __m256d v_left = _mm256_maskload_pd(&input[cur + j - 1],
                                                _mm256_set1_epi64x(0x7FFFFFFFFFFFFFFF));
            /* Right neighbour */
            __m256d v_right = _mm256_maskload_pd(&input[cur + j + 1],
                                                 _mm256_set1_epi64x(0x7FFFFFFFFFFFFFFF));

            __m256d sum = _mm256_add_pd(v_cur, v_up);
            sum = _mm256_add_pd(sum, v_down);
            sum = _mm256_add_pd(sum, v_left);
            sum = _mm256_add_pd(sum, v_right);

            __m256d avg = _mm256_mul_pd(sum, _mm256_set1_pd(inv5));

            /* Store result */
            _mm256_storeu_pd(&output[cur + j], avg);
        }

        /* Scalar fallback for remaining columns */
        for (; j < N; ++j)
        {
            double sum = input[cur + j];

            if (i > 0)       sum += input[top + j];
            if (i + 1 < N)   sum += input[bottom + j];
            if (j > 0)       sum += input[cur + j - 1];
            if (j + 1 < N)   sum += input[cur + j + 1];

            output[cur + j] = sum * inv5;
        }
    }
}
