/* Return the index of the first even number in the vector x.
   Examples:
   input: [7, 3, 9, 5, 5, 7, 2, 9, 12, 11]
   output: 6
   input: [3, 8, 9, 9, 3, 4, 8, 6]
   output: 1
*/
size_t findFirstEven(const std::vector<int>& x) {
    const size_t n = x.size();
    const int* p = x.data();

    /* Process in 256‑bit (8 int) chunks with AVX2 */
    const size_t avxStride = 8;
    size_t i = 0;
    for (; i + avxStride <= n; i += avxStride) {
        // Load 8 int32 values
        __m256i v = _mm256_loadu_si256(reinterpret_cast<const __m256i*>(p + i));
        // Even check: bit 0 (LSB) == 0 -> v & 1 == 0
        __m256i mod2 = _mm256_and_si256(v, _mm256_set1_epi32(1));
        // Create mask where (mod2 == 0)
        __m256i mask = _mm256_cmpeq_epi32(mod2, _mm256_setzero_si256());
        // Get bitmask of the 8 results
        int mm = _mm256_movemask_ps(_mm256_castsi256_ps(mask));
        if (mm) {
            // Find the first set bit
            int offset = __builtin_ctz((unsigned)mm);
            return i + offset;
        }
    }

    /* Handle remaining elements any way (serial) */
    for (; i < n; ++i) {
        if ((p[i] & 1) == 0) {          // even check without modulo
            return i;
        }
    }
    return n;  // not found
}
