```cpp
#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <limits>

struct Point
{
    double x, y;
};

inline double dist2(Point const& a, Point const& b)
{
    double dx = b.x - a.x;
    double dy = b.y - a.y;
    return dx*dx + dy*dy;
}

/* --------------------------------------------------------------------
   Closest‐pair: divide‑and‑conquer implementation.
   Complexity: O(n log n) (average) and O(n) space.
   -------------------------------------------------------------------- */
static std::vector<Point> sortByX(std::vector<Point> const& pts)
{
    std::vector<Point> sorted(pts);
    std::sort(sorted.begin(), sorted.end(), [](Point const& a, Point const& b)
    { return a.x < b.x; });
    return sorted;
}

static void mergeByY(std::vector<Point>& a, std::vector<Point>& left,
                     std::vector<Point>& right)
{
    size_t i = 0, j = 0, k = 0;
    while (i < left.size() && j < right.size())
        a[k++] = (left[i].y <= right[j].y) ? left[i++] : right[j++];
    while (i < left.size()) a[k++] = left[i++];
    while (j < right.size()) a[k++] = right[j++];
}

static double closestRecursive(std::vector<Point>& ptsByY,
                                std::vector<Point> const& xs, size_t l, size_t r)
{
    if (r - l <= 3)                // base case: brute force
    {
        double d = std::numeric_limits<double>::max();
        for (size_t i = l; i < r; ++i)
            for (size_t j = i + 1; j < r; ++j)
                d = std::min(d, dist2(xs[i], xs[j]));
        std::stable_sort(ptsByY.begin() + l, ptsByY.begin() + r,
                         [](Point const& a, Point const& b) { return a.y < b.y; });
        return d;
    }

    size_t mid = l + (r - l) / 2;
    Point midPoint = xs[mid];

    double dLeft  = closestRecursive(ptsByY, xs, l, mid);
    double dRight = closestRecursive(ptsByY, xs, mid, r);
    double d = std::min(dLeft, dRight);

    /* build strip of points within sqrt(d) of mid line */
    std::vector<Point> strip;
    strip.reserve(r - l);
    for (size_t i = l; i < r; ++i)
        if (std::abs(ptsByY[i].x - midPoint.x) < std::sqrt(d))
            strip.push_back(ptsByY[i]);

    /* compare each point with next up to 7 points (y‑sorted) */
    for (size_t i = 0; i < strip.size(); ++i)
    {
        for (size_t j = i + 1; j < strip.size() && (strip[j].y - strip[i].y) < std::sqrt(d); ++j)
            d = std::min(d, dist2(strip[i], strip[j]));
    }
    return d;
}

static std::vector<Point> copyAndSortByX(std::vector<Point> const& pts)
{
    std::vector<Point> res(pts);
    std::sort(res.begin(), res.end(), [](Point const& a, Point const& b)
    { return a.x < b.x; });
    return res;
}

static std::vector<Point> copyAndSortByY(std::vector<Point> const& pts)
{
    std::vector<Point> res(pts);
    std::sort(res.begin(), res.end(), [](Point const& a, Point const& b)
    { return a.y < b.y; });
    return res;
}

/* Public API ---------------------------------------------------------- */
double closestPair(std::vector<Point> const& points)
{
    if (points.size() < 2)
        return 0.0;

    std::vector<Point> pointsByX = copyAndSortByX(points);
    std::vector<Point> pointsByY = copyAndSortByY(points);

    double minDistSq = closestRecursive(pointsByY, pointsByX, 0, points.size());
    return std::sqrt(minDistSq);
}
